import{_ as r,o,c as n,ag as s}from"./chunks/framework.WmBmIPw-.js";const m=JSON.parse('{"title":"遗传算法（Genetic Algorithm, GA）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/genetic-algorithm.md","filePath":"or-opt/genetic-algorithm.md","lastUpdated":1777120239000}'),g={name:"or-opt/genetic-algorithm.md"};function a(e,t,i,l,h,c){return o(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="遗传算法-genetic-algorithm-ga" tabindex="-1">遗传算法（Genetic Algorithm, GA） <a class="header-anchor" href="#遗传算法-genetic-algorithm-ga" aria-label="Permalink to &quot;遗传算法（Genetic Algorithm, GA）&quot;">​</a></h1><p>遗传算法在<strong>有限规模种群</strong>上模拟「选择—交叉—变异—替换」的循环：适者更易被抽为<strong>父本</strong>，<strong>交叉</strong>重组、<strong>变异</strong>扰动，再用<strong>环境选择</strong>把子代/混合群体收成下一代。适合有清晰<strong>编码</strong>与<strong>适应度</strong>的问题，是群体类元启发式的代表。见 <a href="./metaheuristics.html">元启发式总览</a>。（更广义的<strong>进化计算</strong>还包含进化策略、遗传规划等，本页以经典 GA 为主干。）</p><p><strong>适用</strong>：组合或参数优化在能定义可行<strong>编码</strong>、<strong>目标 f 或等价的适应度</strong> 且用单点邻域不划算时；大规模时常与<strong>局部搜索、修复</strong>混合。</p><p><strong>核心</strong>：在一代代循环中，用<strong>选择</strong>调节探索与利用的取舍，用<strong>交叉</strong>在编码空间<strong>重组信息</strong>，用<strong>变异</strong>保多样性，用<strong>替换</strong>决定谁进入下一代、是否<strong>精英</strong>留档。下框为<strong>主循环的完整流程</strong>；其后的四节对<strong>选择、交叉、变异、替换</strong> 分别作展开与常见算子说明。</p><hr><h2 id="算法-最小化示意" tabindex="-1">算法（最小化示意） <a class="header-anchor" href="#算法-最小化示意" aria-label="Permalink to &quot;算法（最小化示意）&quot;">​</a></h2><p>以最小化 f(s) 为例；s 为<strong>个体编码</strong>（二进串、排列、实向量等）。适应度与 f 的关系（直接用 f、取倒数/加常数防负等）须<strong>自始至终结一致</strong>，便于不同代之间比较与选择。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 遗传算法主循环（种群 + 选择 / 交叉 / 变异 / 替换）</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>在可行域上随机或启发式生成初始种群 P，个体数为 N，逐个评价 f。记当前种群里最优为 s⋆；设定：选择方式、交叉与变异算子、交叉率 p_c 与变异率 p_m、代际替换或稳态策略、最大代数或总适应度评价次数、可选精英保留比例等。</p><h3 id="_2-一代迭代-重复直至终止条件" tabindex="-1">2. 一代迭代（重复直至终止条件） <a class="header-anchor" href="#_2-一代迭代-重复直至终止条件" aria-label="Permalink to &quot;2. 一代迭代（重复直至终止条件）&quot;">​</a></h3><ul><li><strong>选择</strong>：由当前 P 中按选择规则选出一批用于繁殖的<strong>父本</strong>（可重复选同一好个体，依锦标赛、轮盘、排序等算子；细节见下节「选择」）。</li><li><strong>交叉</strong>：对父本两两或按算子<strong>配对</strong>，以<strong>交叉率</strong> p_c 在编码上执行交叉，得<strong>子代</strong>中间集；未发生交叉时可将父本<strong>复制</strong>为子代。</li><li><strong>变异</strong>：对子代个体以<strong>变异率</strong> p_m 执行变异（如比特翻、对换、高斯微扰等），<strong>保持或修复</strong>可行性。</li><li><strong>评价与替换</strong>：对子代及（若需）与父代<strong>联合</strong> 评价 f；按<strong>完全代际替换、稳态只换部分个体、精英</strong> 等策略<strong>组成</strong>下一代 P；若出现更优个体则更新 s⋆（细节见下节「替换」）。</li></ul><h3 id="_3-终止" tabindex="-1">3. 终止 <a class="header-anchor" href="#_3-终止" aria-label="Permalink to &quot;3. 终止&quot;">​</a></h3><p>达到预设代数/时间/总适应度评价次数、或 s⋆ 长期不改进等，则停；输出 s⋆。</p></div><p>框内为<strong>可直接依序实现</strong>的主循环；各步可用的具体算子、参数与变体，见下四节分述。</p><hr><h2 id="选择-selection" tabindex="-1">选择（Selection） <a class="header-anchor" href="#选择-selection" aria-label="Permalink to &quot;选择（Selection）&quot;">​</a></h2><p><strong>含义</strong>：在<strong>当前种群</strong>中，按适应度与随机规则，决定<strong>谁参与繁殖、各抽中几次</strong>（<strong>亲本选择</strong>、parent selection）。不决定「谁活到最后」——那由<strong>替换</strong> 一节负责。输出是<strong>带重复的索引/个体集合</strong>，好个体<strong>期望</strong>被多抽，但不保证<strong>全体</strong>最差的从不抽中（视算子而定）。</p><p><strong>常见算子</strong>：</p><ul><li><strong>锦标赛</strong>：在子样本里取<strong>最优</strong> 作为父本之一；子样本大小 k 越大、选择压越强。实现简单、鲁棒。</li><li><strong>轮盘/比例</strong>：选中的概率<strong>正比于</strong>（经线性/σ 等<strong>标度</strong> 后的）适应度；<strong>负目标</strong> 或<strong>尺度</strong> 差异过大时需重新标定，否则<strong>早熟</strong> 或<strong>差别过小</strong>。</li><li><strong>排序/线性排序</strong>：用<strong>名次</strong> 代替原始适应度，减轻尺度敏感；可配合期望拷贝数。</li><li><strong>均匀随机</strong>（少单独用）：无选择压，多在教学或与强精英策略<strong>对照</strong> 时出现。</li></ul><p><strong>注</strong>：<strong>精英</strong> 若与选择绑在一起，通常指<strong>当代最优</strong> 必进<strong>下一代/必参与</strong> 交叉（具体放在实现里，与<strong>替换</strong> 规则对齐）。</p><h2 id="交叉-crossover-recombination" tabindex="-1">交叉（Crossover / Recombination） <a class="header-anchor" href="#交叉-crossover-recombination" aria-label="Permalink to &quot;交叉（Crossover / Recombination）&quot;">​</a></h2><p><strong>含义</strong>：对两个（或多个）<strong>父本</strong> 在<strong>编码串</strong> 上按<strong>切点/掩码/算术</strong> 规则生成<strong>子代</strong>，使子代<strong>同时携带</strong> 双亲的片段。交叉率 p_c 常表示「该对父本<strong>尝试</strong> 交叉」的概率，失败则<strong>直接复制</strong> 父本为子代。交叉与<strong>编码</strong> 强相关，<strong>不可行</strong> 子代要<strong>修</strong> 或<strong>罚</strong> 或<strong>专用算子</strong>。</p><p><strong>离散二进/整数串</strong>：<strong>单点</strong>、<strong>双点</strong>、<strong>均匀</strong> 交叉（位掩码决定来自父 1/父 2）。<strong>背包</strong> 等需保证可行时，有时用<strong>和可行父代</strong> 的交叉或<strong>修复</strong>。</p><p><strong>排列（如 TSP）</strong>：<strong>PMX</strong>（部分映射，减少非法）、<strong>OX</strong>（次序）、<strong>CX</strong> 等，保持或易修复<strong>排列约束</strong>；简单切再粘常产生重复/缺失，需<strong>修复</strong> 或<strong>专用规则</strong>。</p><p><strong>实向量</strong>：<strong>算术交叉</strong>、<strong>混合交叉（BLX-α）</strong>、<strong>模拟二进制 SBX</strong> 等，在<strong>凸组合</strong> 或<strong>区间</strong> 内插值，<strong>边界</strong> 需<strong>截断</strong> 到盒约束。</p><p><strong>注</strong>：<strong>多父</strong> 或<strong>多点</strong> 变体、与问题相关的<strong>问题专用</strong> 重组，文献与库实现中很多，<strong>原则</strong> 仍是：子代应落在<strong>约定可行域</strong> 上或带明确<strong>惩罚/修复</strong>。</p><h2 id="变异-mutation" tabindex="-1">变异（Mutation） <a class="header-anchor" href="#变异-mutation" aria-label="Permalink to &quot;变异（Mutation）&quot;">​</a></h2><p><strong>含义</strong>：对<strong>一个</strong> 个体在编码上做<strong>小概率、局部</strong> 改动，为种群<strong>续多样性</strong>、避免交叉长期只在<strong>子空间</strong> 内<strong>重组</strong>。变异率 p_m 常按<strong>位/基因</strong> 或<strong>个体</strong> 定义；p_m 过大则退化为<strong>随机搜索</strong>，过小则<strong>早熟</strong>。</p><p><strong>二进/整数串</strong>：<strong>翻位</strong>、<strong>随机摄动某一维</strong> 等。<br><strong>排列</strong>：<strong>对换、插入、反序</strong> 等<strong>邻域</strong> 型一步。<br><strong>实向量</strong>：<strong>高斯/均匀</strong> 小步，或只扰动<strong>部分维</strong>；有界时<strong>截断</strong>。</p><p><strong>自适应性/动态</strong>：随代数<strong>降低/升高</strong> 变异、或据<strong>群体多样性</strong> 调 p_m，属实现细节，<strong>目标</strong> 仍是平衡<strong>搜索</strong> 与<strong>稳定</strong>。</p><h2 id="替换-replacement-环境选择" tabindex="-1">替换（Replacement / 环境选择） <a class="header-anchor" href="#替换-replacement-环境选择" aria-label="Permalink to &quot;替换（Replacement / 环境选择）&quot;">​</a></h2><p><strong>含义</strong>：在「经交叉、变异并评价后」的群体与<strong>原种群</strong> 之间，决定<strong>谁</strong> 成为<strong>下一代</strong> 的 P（<strong>环境选择</strong>、survivor selection）。与<strong>选择</strong> 的区别：<strong>选择</strong> 管<strong>生谁当父母</strong>，<strong>替换</strong> 管<strong>谁</strong> 在<strong>下代</strong> 里<strong>存活</strong>（或<strong>占坑</strong> 多少）。</p><p><strong>代际/一代一代（generational）</strong>：子代<strong>全体</strong> 替换 P（或<strong>仅子代</strong> 中最好的 N 个成新 P），父代<strong>除精英外</strong> 常<strong>不再保留</strong>。最简形式需配合<strong>精英</strong> 以免 s⋆ 被偶然洗掉。<br><strong>稳态/一代接一代（steady-state）</strong>：每步<strong>只</strong> 用<strong>一个或少数</strong> 新子代<strong>替换</strong> P 中<strong>最差</strong> 或<strong>随机</strong> 者，P 的<strong>规模</strong> 不变、<strong>更平滑</strong> 的进度曲线。<br><strong>(μ+λ) / (μ,λ) 式叙述</strong>：有文献用「μ 个父、λ 个子」：<strong>(μ+λ)</strong> 为父母与子<strong>联合</strong> 取最好的 μ 个；<strong>(μ,λ)</strong> 为<strong>只</strong> 从<strong>子</strong> 里选 μ 个，<strong>不保留</strong> 未选父本（<strong>更激进</strong>）。经典 GA 叙述常<strong>不</strong> 严格用这套符号，但<strong>思想</strong> 与<strong>精英、稳态</strong> 可对照。</p><p><strong>精英（elitism）</strong>：当代（或<strong>历史</strong>）<strong>最优</strong> 个体<strong>必进</strong> 下一代或<strong>单独</strong> 存档，是防<strong>好解</strong> 在随机<strong>交叉变异</strong> 中<strong>丢失</strong> 的<strong>常用</strong> 手段；精英<strong>份额</strong> 过大也会<strong>减多样性</strong>。</p><hr><h2 id="与同类方法的差异-提要" tabindex="-1">与同类方法的差异（提要） <a class="header-anchor" href="#与同类方法的差异-提要" aria-label="Permalink to &quot;与同类方法的差异（提要）&quot;">​</a></h2><ul><li>相对<strong>单点</strong> 方法（<a href="./simulated-annealing.html">模拟退火</a>、<a href="./tabu-search.html">禁忌搜索</a>）：<strong>多解并行</strong> 搜索，由<strong>选择—交叉</strong> 在<strong>编码</strong> 上<strong>大跳</strong>，不必每步定义<strong>邻域</strong>；但<strong>算子</strong> 与<strong>调参</strong> 与问题<strong>强绑定</strong>。</li><li>常与<strong>局部搜索</strong>（memetic）或<strong>多目标</strong> 族结合，本页不展开。</li></ul><h2 id="参考阅读" tabindex="-1">参考阅读 <a class="header-anchor" href="#参考阅读" aria-label="Permalink to &quot;参考阅读&quot;">​</a></h2><ul><li>Holland 的经典 GA 思想；Michalewicz 等关于<strong>实参/排列编码与算子</strong> 的整理；各应用领域的「编码 + 选择 + 交叉 + 替换」<strong>可复现</strong> 案例。</li><li>实现时建议把<strong>选择、交叉、变异、替换</strong> 各自做成<strong>可替换</strong> 的模块，<strong>日志</strong> 记录代数、最优值与<strong>算子</strong> 设置，方便对比<strong>基线</strong>。</li></ul>',34)])])}const d=r(g,[["render",a]]);export{m as __pageData,d as default};
